import React, { useCallback, useEffect, useRef, useState } from "react";
import "./App.css";

const API_URL = "http://127.0.0.1:8000";

const templates = [
  {
    name: "Generic",
    value: "generic",
    description: "A clean, flexible starter layout for any small business.",
  },
  {
    name: "Modern",
    value: "modern",
    description: "Bold spacing, crisp sections, and a contemporary feel.",
  },
  {
    name: "Luxury",
    value: "luxury",
    description: "Elegant presentation for premium brands and services.",
  },
];

function App() {
  const iframeRef = useRef(null);
  const [page, setPage] = useState("login");
  const [step, setStep] = useState(1);
  const [idea, setIdea] = useState("");
  const [html, setHtml] = useState("");
  const [loading, setLoading] = useState(false);
  const [savingEdits, setSavingEdits] = useState(false);
  const [savingProject, setSavingProject] = useState(false);
  const [projectId, setProjectId] = useState(null);
  const [template, setTemplate] = useState("generic");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [authMessage, setAuthMessage] = useState("");
  const [authError, setAuthError] = useState("");
  const [projects, setProjects] = useState([]);
  const [statusText, setStatusText] = useState("AI is drafting content...");
  const [logo, setLogo] = useState("");
  const [selectedImgIndex, setSelectedImgIndex] = useState(null);

  useEffect(() => {
    if (!loading) {
      setStatusText("AI is drafting content...");
      return;
    }

    const statuses = [
      "AI is drafting content...",
      "Analyzing business idea keywords...",
      "Sourcing relevant images...",
      "Assembling template sections...",
      "Applying style framework...",
      "Almost ready..."
    ];

    let current = 0;
    const interval = setInterval(() => {
      current = (current + 1) % statuses.length;
      setStatusText(statuses[current]);
    }, 2500);

    return () => clearInterval(interval);
  }, [loading]);

  const resetAuthFeedback = () => {
    setAuthMessage("");
    setAuthError("");
  };

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();

    reader.onload = () => {
      const iframe = iframeRef.current;
      if (!iframe?.contentDocument) return;

      const imgs = iframe.contentDocument.querySelectorAll("img");
      let img = null;
      if (selectedImgIndex !== null && selectedImgIndex < imgs.length) {
        img = imgs[selectedImgIndex];
      } else {
        img = iframe.contentDocument.querySelector("img.section-img") || iframe.contentDocument.querySelector("img");
      }

      if (img) {
        img.src = reader.result;
      }
    };

    reader.readAsDataURL(file);
  };

  const handleLogoUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();

    reader.onload = () => {
      setLogo(reader.result);

      const iframe = iframeRef.current;
      const logoImg = iframe?.contentDocument?.querySelector("img.logo");
      if (logoImg) {
        logoImg.src = reader.result;
      }
    };

    reader.readAsDataURL(file);
  };

  const getRenderedHtml = () => {
    if (!html) return "";
    let rendered = html;
    if (logo) {
      rendered = rendered
        .replace(/src="{{logo}}"/g, `src="${logo}"`)
        .replace(/src="https:\/\/via\.placeholder\.com\/80"/g, `src="${logo}"`)
        .replace(/src="https:\/\/placehold\.co\/80"/g, `src="${logo}"`);
    }
    return rendered;
  };

  const enablePreviewEditing = useCallback(() => {
    const iframe = iframeRef.current;
    const doc = iframe?.contentDocument;

    if (!doc?.body) {
      return;
    }

    doc.querySelectorAll("p, h1, h2, li").forEach((element) => {
      element.contentEditable = true;
    });

    if (!doc.getElementById("preview-editor-style")) {
      const style = doc.createElement("style");
      style.id = "preview-editor-style";
      style.innerHTML = `
        [contenteditable="true"] {
          outline: 1px dashed #4a6cf7;
          cursor: text;
        }
        img {
          transition: outline 0.2s;
        }
        img:hover {
          outline: 2px dashed #4a6cf7;
        }
        .hero {
          transition: outline 0.2s;
        }
        .hero:hover {
          outline: 2px dashed #4a6cf7;
        }
      `;
      doc.head.appendChild(style);
    }

    // Attach click listeners to all images to change source on click or select for upload
    doc.querySelectorAll("img").forEach((img, index) => {
      img.style.cursor = "pointer";
      img.onclick = (e) => {
        e.stopPropagation();

        // Remove previous selection outlines and apply to this image
        doc.querySelectorAll("img").forEach(i => i.style.outline = "");
        img.style.outline = "3px solid #4a6cf7";

        // Set selected index
        setSelectedImgIndex(index);

        const newUrl = prompt("Enter new image URL (or select a file under 'Upload Section Image'):");
        if (newUrl) {
          img.src = newUrl;
        }
      };
    });

    // Attach click listener to the hero block for editing background
    const hero = doc.querySelector(".hero");
    if (hero) {
      hero.style.cursor = "pointer";
      hero.onclick = (e) => {
        // Trigger background change only if clicking hero layout container itself
        if (e.target === hero || e.target.classList.contains("overlay")) {
          e.stopPropagation();
          const currentBg = hero.style.backgroundImage || "";
          const currentUrl = currentBg.replace(/^url\(['"]?/, '').replace(/['"]?\)$/, '');
          const newUrl = prompt("Enter new hero background image URL:", currentUrl);
          if (newUrl) {
            hero.style.backgroundImage = `url('${newUrl}')`;
          }
        }
      };
    }
  }, [setSelectedImgIndex]);

  useEffect(() => {
    const iframe = iframeRef.current;

    if (!iframe) {
      return;
    }

    iframe.onload = enablePreviewEditing;
  }, [enablePreviewEditing, html]);

  const readError = async (res, fallback) => {
    try {
      const text = await res.text();

      if (!text) {
        return fallback;
      }

      try {
        const data = JSON.parse(text);
        return data.detail || data.error || fallback;
      } catch {
        return text;
      }
    } catch {
      return fallback;
    }
  };

  const signup = async (event) => {
    event.preventDefault();
    resetAuthFeedback();

    if (!email.trim() || !password) {
      setAuthError("Enter an email and password to create your account.");
      return;
    }

    try {
      const res = await fetch(`${API_URL}/signup`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          email: email.trim(),
          password,
        }),
      });

      if (!res.ok) {
        setAuthError(await readError(res, "Signup failed."));
        return;
      }

      setAuthMessage("Account created. You can log in now.");
      setPage("login");
      setPassword("");
    } catch {
      setAuthError("Unable to reach the server. Is the backend running?");
    }
  };

  const login = async (event) => {
    event.preventDefault();
    resetAuthFeedback();

    if (!email.trim() || !password) {
      setAuthError("Enter your email and password.");
      return;
    }

    try {
      const res = await fetch(`${API_URL}/login`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          email: email.trim(),
          password,
        }),
      });

      if (!res.ok) {
        setAuthError(await readError(res, "Login failed."));
        return;
      }

      const data = await res.json();

      if (!data.access_token) {
        setAuthError("Login response did not include an access token.");
        return;
      }

      localStorage.setItem("token", data.access_token);
      setAuthMessage("Login successful.");
      setPassword("");
      setProjectId(null);
      setStep(1);
      setPage("dashboard");
    } catch {
      setAuthError("Unable to reach the server. Is the backend running?");
    }
  };

  const logout = () => {
    localStorage.removeItem("token");
    setHtml("");
    setIdea("");
    setTemplate("generic");
    setProjectId(null);
    setStep(1);
    setProjects([]);
    setPage("login");
    setAuthMessage("You have been logged out.");
  };

  const generateWebsite = async () => {
    if (!idea.trim()) {
      alert("Enter a business idea");
      return;
    }

    const token = localStorage.getItem("token");

    if (!token) {
      setPage("login");
      setAuthError("Please log in first.");
      return;
    }

    setLoading(true);

    try {
      const res = await fetch(`${API_URL}/generate-ai`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          idea,
          template,
        }),
      });

      if (!res.ok) {
        alert(`Error: ${await readError(res, "Something went wrong")}`);
        return;
      }

      const data = await res.json();

      if (data.error) {
        alert(`Error: ${data.error}`);
        return;
      }

      setHtml(data.html);
      setProjectId(null);
      setStep(4);
      setPage("preview");
    } catch {
      alert("Unable to reach the server");
    } finally {
      setLoading(false);
    }
  };

  const fetchProjects = async () => {
    const token = localStorage.getItem("token");

    if (!token) {
      setPage("login");
      setAuthError("Please log in first.");
      return;
    }

    try {
      const res = await fetch(`${API_URL}/projects`, {
        headers: {
          Authorization: `Bearer ${token}`,
        },
      });

      if (!res.ok) {
        alert(await readError(res, "Error fetching projects"));
        return;
      }

      const data = await res.json();
      setProjects(Array.isArray(data) ? data : []);
    } catch {
      alert("Unable to reach the server");
    }
  };

  useEffect(() => {
    if (page === "projects") {
      fetchProjects();
    }
    // fetchProjects intentionally uses the latest token and state when projects opens.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page]);

  const downloadWebsite = () => {
    if (!html) {
      alert("Generate a website first!");
      return;
    }

    const blob = new Blob([html], { type: "text/html" });
    const link = document.createElement("a");

    link.href = URL.createObjectURL(blob);
    link.download = "website.html";
    link.click();
    URL.revokeObjectURL(link.href);
  };

  const saveEdits = async () => {
    const iframe = iframeRef.current;
    const token = localStorage.getItem("token");

    if (!token) {
      setPage("login");
      setAuthError("Please log in first.");
      return;
    }

    if (!projectId) {
      alert("Generate or open a saved project before saving edits.");
      return;
    }

    if (!iframe?.contentDocument?.documentElement) {
      alert("Preview is not ready yet.");
      return;
    }

    const updatedBodyHtml = iframe.contentDocument.body.innerHTML;
    const updatedHtml = iframe.contentDocument.documentElement.outerHTML;

    // Scrape updated image URLs and logo from the iframe to keep data_json updated
    const logoImg = iframe.contentDocument.querySelector("img.logo")?.src || "";

    const heroBg = iframe.contentDocument.querySelector(".hero")?.style.backgroundImage || "";
    const heroUrl = heroBg.replace(/^url\(['"]?/, "").replace(/['"]?\)$/, "");

    const sectionImages = iframe.contentDocument.querySelectorAll("img.section-img");
    const aboutUrl = sectionImages[0]?.src || "";
    const servicesUrl = sectionImages[1]?.src || "";

    const updatedData = {
      images: {
        logo: logoImg,
        hero: heroUrl,
        about: aboutUrl,
        services: servicesUrl
      }
    };

    setSavingEdits(true);

    try {
      const res = await fetch(`${API_URL}/update-project`, {
        method: "PUT",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          project_id: projectId,
          html: updatedHtml,
          body_html: updatedBodyHtml,
          data: updatedData
        }),
      });

      if (!res.ok) {
        alert(`Error: ${await readError(res, "Could not save edits")}`);
        return;
      }

      setHtml(updatedHtml);
      alert("Changes saved successfully.");
    } catch {
      alert("Unable to reach the server");
    } finally {
      setSavingEdits(false);
    }
  };

  const saveProject = async () => {
    const token = localStorage.getItem("token");
    const iframe = iframeRef.current;

    if (!token) {
      setPage("login");
      setAuthError("Please log in first.");
      return;
    }

    if (!html) {
      alert("Generate a website before saving.");
      return;
    }

    const currentHtml = iframe?.contentDocument?.documentElement
      ? iframe.contentDocument.documentElement.outerHTML
      : getRenderedHtml();

    setSavingProject(true);

    try {
      const res = await fetch(`${API_URL}/save-project`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify({
          name: idea,
          template: template,
          html: currentHtml,
        }),
      });

      if (!res.ok) {
        alert(`Error: ${await readError(res, "Could not save project")}`);
        return;
      }

      const data = await res.json();
      setHtml(currentHtml);
      setProjectId(data.project_id || null);
      alert("Project saved successfully.");
      setPage("projects");
    } catch {
      alert("Unable to reach the server");
    } finally {
      setSavingProject(false);
    }
  };

  const switchAuthPage = (nextPage) => {
    resetAuthFeedback();
    setPassword("");
    setPage(nextPage);
  };

  const continueFromIdea = () => {
    if (!idea.trim()) {
      alert("Enter a business idea");
      return;
    }

    setStep(3);
  };

  const resetBuilder = () => {
    setIdea("");
    setHtml("");
    setTemplate("generic");
    setProjectId(null);
    setLogo("");
    setSelectedImgIndex(null);
    setStep(1);
  };

  const openProject = (project) => {
    setIdea(project.name || "");
    setHtml(project.html || "");
    setTemplate(project.template || "generic");
    setProjectId(project.id);

    try {
      const projData = JSON.parse(project.data_json);
      if (projData?.images?.logo) {
        setLogo(projData.images.logo);
      } else {
        setLogo("");
      }
    } catch {
      setLogo("");
    }

      setSelectedImgIndex(null);
    setPage("preview");
    setStep(4);
  };
  const deleteProject = async (id) => {
  const token = localStorage.getItem("token");

  if (!window.confirm("Delete this project?")) return;

  try {
    await fetch(`http://127.0.0.1:8000/delete-project/${id}`, {
      method: "DELETE",
      headers: {
        "Authorization": `Bearer ${token}`
      }
    });

    alert("Deleted ✅");
    fetchProjects(); // refresh list
  } catch {
    alert("Delete failed ❌");
  }
};

  const isSignup = page === "signup";
  const wizardSteps = [
    { number: 1, label: "Template" },
    { number: 2, label: "Idea" },
    { number: 3, label: "Generate" },
    { number: 4, label: "Preview" },
  ];

  return (
    <div className="container">
      <header className="app-header">
        <div>
          <h1>AI Website Builder</h1>
          <p>Generate and save simple business websites.</p>
        </div>

        {page !== "login" && page !== "signup" && (
          <button className="secondary-btn header-btn" onClick={logout}>
            Logout
          </button>
        )}
      </header>

      {(page === "login" || page === "signup") && (
        <form className="card auth-card" onSubmit={isSignup ? signup : login}>
          <h2>{isSignup ? "Create account" : "Login"}</h2>
          <p className="muted">
            {isSignup
              ? "Sign up to start saving generated websites."
              : "Welcome back. Enter your details to continue."}
          </p>

          {authMessage && <p className="success-message">{authMessage}</p>}
          {authError && <p className="error-message">{authError}</p>}

          <label>
            Email
            <input
              type="email"
              placeholder="you@example.com"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              autoComplete="email"
            />
          </label>

          <label>
            Password
            <input
              type="password"
              placeholder="Enter your password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              autoComplete={isSignup ? "new-password" : "current-password"}
            />
          </label>

          <button type="submit">{isSignup ? "Sign up" : "Login"}</button>

          <button
            className="link-btn"
            type="button"
            onClick={() => switchAuthPage(isSignup ? "login" : "signup")}
          >
            {isSignup
              ? "Already have an account? Login"
              : "Need an account? Sign up"}
          </button>
        </form>
      )}

      {page === "dashboard" && (
        <div className="dashboard-grid">
          <section className="card dashboard-card">
            <div className="section-heading">
              <h2>Welcome</h2>
              <p className="muted">
                Create a new website or continue editing a saved project.
              </p>
            </div>

            <div className="button-group">
              <button onClick={() => {
                resetBuilder();
                setPage("generator");
              }}>
                Create Website
              </button>
              <button className="secondary-btn" onClick={() => setPage("projects")}>
                My Projects
              </button>
            </div>
          </section>
        </div>
      )}

      {(page === "generator" || page === "preview") && (
        <div className="builder-shell">
          <nav className="stepper" aria-label="Website builder progress">
            {wizardSteps.map((item) => (
              <div
                className={`stepper-item ${step === item.number ? "active" : ""} ${
                  step > item.number ? "complete" : ""
                }`}
                key={item.number}
              >
                <span>{item.number}</span>
                <strong>{item.label}</strong>
              </div>
            ))}
          </nav>

          <div className="card generator-card">
            {step === 1 && (
              <section className="template-section" aria-labelledby="template-heading">
                <div className="section-heading">
                  <h2 id="template-heading">Choose a template</h2>
                  <p className="muted">Pick the visual direction for your website.</p>
                </div>

                <div className="template-gallery">
                  {templates.map((item) => {
                    const selected = template === item.value;

                    return (
                      <button
                        className={`template-card ${selected ? "selected" : ""}`}
                        type="button"
                        key={item.value}
                        onClick={() => setTemplate(item.value)}
                        aria-pressed={selected}
                      >
                        <img
                          src={`/templates/${item.value}-preview.png`}
                          alt={`${item.name} template preview`}
                          className="template-preview-image"
                        />

                        <span className="template-copy">
                          <strong>{item.name}</strong>
                          <span>{item.description}</span>
                        </span>
                      </button>
                    );
                  })}
                </div>

                <div className="button-group align-end">
                  <button onClick={() => setStep(2)}>Continue</button>
                </div>
              </section>
            )}

            {step === 2 && (
              <section className="wizard-panel">
                <div className="section-heading">
                  <h2>Describe your business</h2>
                  <p className="muted">
                    Start with the idea, audience, or service you want the website to explain.
                  </p>
                </div>

                <label>
                  Business idea
                  <input
                    type="text"
                    placeholder="Example: a premium coffee shop in Chennai"
                    value={idea}
                    onChange={(e) => setIdea(e.target.value)}
                  />
                </label>

                <div className="button-group">
                  <button className="secondary-btn" onClick={() => setStep(1)}>
                    Back
                  </button>
                  <button onClick={continueFromIdea}>Continue</button>
                </div>
              </section>
            )}

            {step === 3 && (
              <section className="wizard-panel">
                {loading ? (
                  <div className="skeleton-container" aria-label="Generating your website...">
                    <div className="skeleton-header">
                      <div className="skeleton-line skeleton-title shimmer"></div>
                      <div className="skeleton-line skeleton-subtitle shimmer"></div>
                    </div>
                    <div className="skeleton-hero-container">
                      <div className="skeleton-hero shimmer">
                        <div className="skeleton-hero-content">
                          <div className="skeleton-line shimmer-light" style={{ width: "40%", height: "20px", margin: "0 auto 10px" }}></div>
                          <div className="skeleton-line shimmer-light" style={{ width: "60%", height: "14px", margin: "0 auto" }}></div>
                        </div>
                      </div>
                    </div>
                    <div className="skeleton-section-item">
                      <div className="skeleton-line skeleton-section-title shimmer" style={{ width: "25%", height: "18px", marginBottom: "12px" }}></div>
                      <div className="skeleton-image-placeholder shimmer" style={{ height: "140px", borderRadius: "8px", marginBottom: "12px" }}></div>
                      <div className="skeleton-line shimmer" style={{ width: "90%", height: "12px", marginBottom: "8px" }}></div>
                      <div className="skeleton-line shimmer" style={{ width: "75%", height: "12px" }}></div>
                    </div>
                    <div className="skeleton-status">
                      <div className="loader-inline"></div>
                      <span className="skeleton-status-text">{statusText}</span>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="section-heading">
                      <h2>Generate Website</h2>
                      <p className="muted">
                        Review your choices, then generate a website preview.
                      </p>
                    </div>

                    <div className="review-grid">
                      <div>
                        <span>Business idea</span>
                        <strong>{idea}</strong>
                      </div>
                      <div>
                        <span>Template</span>
                        <strong>{templates.find((item) => item.value === template)?.name}</strong>
                      </div>
                    </div>

                    <div className="button-group">
                      <button
                        className="secondary-btn"
                        onClick={() => setStep(2)}
                        disabled={loading}
                      >
                        Back
                      </button>
                      <button onClick={generateWebsite} disabled={loading}>
                        Generate Website
                      </button>
                    </div>
                  </>
                )}
              </section>
            )}

            {page === "preview" && step === 4 && (
              <section className="wizard-panel">
                <div className="preview-header">
                  <div>
                    <h2>Preview Website</h2>
                    <p className="muted">Your generated website is ready to review.</p>
                  </div>
                  <button className="secondary-btn compact-btn" onClick={resetBuilder}>
                    Create Another Website
                  </button>
                </div>

                <div className="editor-controls-panel">
                  <div className="control-item">
                    <label>Upload Logo</label>
                    <input type="file" accept="image/*" onChange={handleLogoUpload} />
                  </div>
                  <div className="control-item">
                    <label>Upload Section Image</label>
                    <input type="file" accept="image/*" onChange={handleImageUpload} />
                    <span className="control-help">Click an image in the preview to select it first.</span>
                  </div>
                </div>

                <div className="preview">
                  <iframe
                    title="preview"
                    srcDoc={getRenderedHtml()}
                    ref={iframeRef}
                    onLoad={enablePreviewEditing}
                  />
                </div>

                <div className="button-group">
                  <button onClick={saveEdits} disabled={savingEdits}>
                    {savingEdits ? "Saving..." : "Save Changes"}
                  </button>

                  <button className="download-btn" onClick={downloadWebsite}>
                    Download
                  </button>

                  <button
                    className="secondary-btn"
                    onClick={saveProject}
                    disabled={savingProject}
                  >
                    {savingProject ? "Saving..." : "Save Project"}
                  </button>

                  <button className="secondary-btn" onClick={() => setPage("projects")}>
                    My Projects
                  </button>
                </div>
              </section>
            )}
          </div>
        </div>
      )}

    <div className="card">
      <h3>My Projects</h3>

      {projects.length === 0 ? (
        <p>No projects yet</p>
      ) : (
        <>
          {projects.map((p) => (
            <div key={p.id} className="project-card">
              <strong>{p.name}</strong>

              <div className="project-actions">
                <button onClick={() => setHtml(p.html)}>
                  Open
                </button>

                <button
                  className="delete-btn"
                  onClick={() => deleteProject(p.id)}
                >
                  Delete ❌
                </button>
              </div>
            </div>
          ))}
        </>
      )}
    </div>

  </div>
);
}

export default App;
